+"use client";
+
+import { useEffect, useMemo, useState } from "react";
+
+type Card = {
+  id: string;
+  tone: string;
+  label: string;
+  flipped: boolean;
+  matched: boolean;
+  position: { x: number; y: number };
+};
+
+const COLOR_PALETTE = [
+  { tone: "#ef4444", label: "紅" },
+  { tone: "#f97316", label: "橙" },
+  { tone: "#eab308", label: "黃" },
+  { tone: "#22c55e", label: "綠" },
+  { tone: "#3b82f6", label: "藍" },
+  { tone: "#8b5cf6", label: "紫" },
+  { tone: "#ec4899", label: "粉" },
+  { tone: "#14b8a6", label: "青" }
+];
+
+const SLOT_POSITIONS = [
+  { x: 18, y: 18 },
+  { x: 50, y: 18 },
+  { x: 82, y: 18 },
+  { x: 18, y: 46 },
+  { x: 50, y: 46 },
+  { x: 82, y: 46 },
+  { x: 18, y: 74 },
+  { x: 50, y: 74 },
+  { x: 82, y: 74 },
+  { x: 34, y: 30 },
+  { x: 66, y: 30 },
+  { x: 34, y: 62 },
+  { x: 66, y: 62 }
+];
+
+function shuffle<T>(items: T[]): T[] {
+  const list = [...items];
+  for (let i = list.length - 1; i > 0; i -= 1) {
+    const j = Math.floor(Math.random() * (i + 1));
+    [list[i], list[j]] = [list[j], list[i]];
+  }
+  return list;
+}
+
+function buildRound(round: number): Card[] {
+  const pairCount = Math.min(2 + round, COLOR_PALETTE.length);
+  const pickedColors = shuffle(COLOR_PALETTE).slice(0, pairCount);
+  const deck = shuffle(
+    pickedColors.flatMap((item, idx) => [
+      { id: `${idx}-a`, tone: item.tone, label: item.label },
+      { id: `${idx}-b`, tone: item.tone, label: item.label }
+    ])
+  );
+  const positions = shuffle(SLOT_POSITIONS).slice(0, deck.length);
+
+  return deck.map((item, index) => ({
+    ...item,
+    flipped: false,
+    matched: false,
+    position: positions[index]
+  }));
+}
+
+export default function Home() {
+  const [round, setRound] = useState(1);
+  const [score, setScore] = useState(0);
+  const [cards, setCards] = useState<Card[]>(() => buildRound(1));
+  const [openedIds, setOpenedIds] = useState<string[]>([]);
+  const [locked, setLocked] = useState(false);
+
+  const matchedCount = useMemo(() => cards.filter((card) => card.matched).length, [cards]);
+
+  useEffect(() => {
+    if (matchedCount === cards.length && cards.length > 0) {
+      const timer = window.setTimeout(() => {
+        setRound((prev) => prev + 1);
+      }, 700);
+      return () => window.clearTimeout(timer);
+    }
+    return undefined;
+  }, [cards.length, matchedCount]);
+
+  useEffect(() => {
+    setCards(buildRound(round));
+    setOpenedIds([]);
+    setLocked(false);
+  }, [round]);
+
+  const onFlip = (id: string) => {
+    if (locked) return;
+
+    const card = cards.find((item) => item.id === id);
+    if (!card || card.flipped || card.matched) return;
+
+    const nextOpened = [...openedIds, id];
+    setOpenedIds(nextOpened);
+    setCards((prev) => prev.map((item) => (item.id === id ? { ...item, flipped: true } : item)));
+
+    if (nextOpened.length === 2) {
+      setLocked(true);
+      const [firstId, secondId] = nextOpened;
+      const first = cards.find((item) => item.id === firstId);
+      const second = cards.find((item) => item.id === secondId);
+      const isMatch = first?.tone === second?.tone;
+
+      window.setTimeout(() => {
+        if (isMatch) {
+          setCards((prev) =>
+            prev.map((item) =>
+              item.id === firstId || item.id === secondId ? { ...item, matched: true } : item
+            )
+          );
+          setScore((prev) => prev + 5);
+        } else {
+          setCards((prev) =>
+            prev.map((item) =>
+              item.id === firstId || item.id === secondId ? { ...item, flipped: false } : item
+            )
+          );
+        }
+        setOpenedIds([]);
+        setLocked(false);
+      }, 650);
+    }
+  };
+
+  const restart = () => {
+    setRound(1);
+    setScore(0);
+    setCards(buildRound(1));
+    setOpenedIds([]);
+    setLocked(false);
+  };
+
+  return (
+    <main className="game-shell">
+      <div className="game-stage">
+        <header className="hud">
+          <p>
+            Round {round} <span>|</span> Score {score}
+          </p>
+        </header>
+
+        <section className="board" aria-label="matching board">
+          {cards.map((card) => (
+            <button
+              type="button"
+              key={card.id}
+              className={`memory-card ${card.flipped || card.matched ? "is-flipped" : ""}`}
+              style={{ left: `${card.position.x}%`, top: `${card.position.y}%` }}
+              onClick={() => onFlip(card.id)}
+              aria-label={`翻開${card.label}色卡牌`}
+            >
+              <span className="memory-card-inner">
+                <span className="memory-card-face memory-card-back">
+                  <span>🐱</span>
+                </span>
+                <span className="memory-card-face memory-card-front" style={{ background: card.tone }}>
+                  {card.label}
+                </span>
+              </span>
+            </button>
+          ))}
+        </section>
+
+        <footer className="game-footer">
+          <button type="button" onClick={restart}>
+            重新開始
+          </button>
+        </footer>
+      </div>
+    </main>
+  );
+}
